import{c as a,Q as t,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Agent Harness Engineering","description":"","frontmatter":{"title":"Agent Harness Engineering","author":"Addy Osmani","date":"2026-04-30T00:00:00.000Z","source":"https://addyosmani.com/blog/agent-harness-engineering/","tags":["agent-harness","research"]},"headers":[],"relativePath":"research/agent-harness/references/2026-04-30-agent-harness-engineering-addy-osmani.md","filePath":"research/agent-harness/references/2026-04-30-agent-harness-engineering-addy-osmani.md","lastUpdated":1779894392000}'),o={name:"research/agent-harness/references/2026-04-30-agent-harness-engineering-addy-osmani.md"};function r(i,e,l,c,h,d){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="agent-harness-engineering" tabindex="-1">Agent Harness Engineering <a class="header-anchor" href="#agent-harness-engineering" aria-label="Permalink to &quot;Agent Harness Engineering&quot;">​</a></h1><h2 id="central-thesis" tabindex="-1">Central Thesis <a class="header-anchor" href="#central-thesis" aria-label="Permalink to &quot;Central Thesis&quot;">​</a></h2><p>&quot;A decent model with a great harness beats a great model with a bad harness.&quot; The article argues that AI agent capability emerges primarily from the scaffolding surrounding the model, not the model itself.</p><h2 id="key-definition" tabindex="-1">Key Definition <a class="header-anchor" href="#key-definition" aria-label="Permalink to &quot;Key Definition&quot;">​</a></h2><p><strong>Agent Harness</strong> = Model + all surrounding infrastructure</p><p>The harness encompasses: system prompts, tools, execution sandboxes, feedback loops, hooks, memory systems, and observability—everything except the model weights.</p><h2 id="core-equation" tabindex="-1">Core Equation <a class="header-anchor" href="#core-equation" aria-label="Permalink to &quot;Core Equation&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>coding agent = AI model(s) + harness</span></span></code></pre></div><h2 id="essential-components" tabindex="-1">Essential Components <a class="header-anchor" href="#essential-components" aria-label="Permalink to &quot;Essential Components&quot;">​</a></h2><p><strong>Filesystem &amp; Git</strong>: Durable state and versioning foundation</p><p><strong>Bash &amp; Code Execution</strong>: General-purpose tool capability</p><p><strong>Sandboxes</strong>: Safe, isolated execution environments</p><p><strong>Memory Systems</strong>: Continual learning via <code>AGENTS.md</code> and context injection</p><p><strong>Context Management</strong>: Compaction, tool offloading, skill disclosure</p><p><strong>Long-Horizon Execution</strong>: Ralph Loops, planning, verification cycles</p><p><strong>Hooks</strong>: Enforcement layer (typecheck, linting, destructive-action blocks)</p><h2 id="notable-quote" tabindex="-1">Notable Quote <a class="header-anchor" href="#notable-quote" aria-label="Permalink to &quot;Notable Quote&quot;">​</a></h2><p>&quot;Every line in a good <code>AGENTS.md</code> should be traceable back to a specific thing that went wrong.&quot;</p><h2 id="the-ratchet-principle" tabindex="-1">The &quot;Ratchet&quot; Principle <a class="header-anchor" href="#the-ratchet-principle" aria-label="Permalink to &quot;The &quot;Ratchet&quot; Principle&quot;">​</a></h2><p>Convert each agent failure into permanent rules—the harness tightens with every mistake.</p><h2 id="critical-data-point" tabindex="-1">Critical Data Point <a class="header-anchor" href="#critical-data-point" aria-label="Permalink to &quot;Critical Data Point&quot;">​</a></h2><p>Claude Opus 4.6 in Claude Code scores lower than the same model in custom harnesses optimized for specific tasks (Top 30 → Top 5 on Terminal Bench 2.0 by harness changes alone).</p><h2 id="architecture-pattern" tabindex="-1">Architecture Pattern <a class="header-anchor" href="#architecture-pattern" aria-label="Permalink to &quot;Architecture Pattern&quot;">​</a></h2><p>Harnesses now follow convergent design: input layers, knowledge layers, integration with MCPs, execution dispatch, output verification, and multi-agent orchestration.</p>',24)])])}const u=a(o,[["render",r]]);export{g as __pageData,u as default};
